INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('64731592-72df-4419-8ff2-dd2886533a53', 'LWW_Q2_2025_MOV_005', 'Điền vào chỗ trống', '{"hints": [], "title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "They walked slowly and quietly for two hours. They saw birds and they saw some fish which were swimming in the river. Then, they saw a big brown bear. The children shouted, \"Help!\" and started to run. They were very frightened. Jane stopped and looked back. \"Stop!\" she shouted loudly and all the girls stopped. \"What''s the matter?\" they asked Jane. When they looked again, they couldn''t see the bear.", "imageUrl": "questions/images/1773883656748_24bfd055_q2_mov_rw_p5_2.png", "question": "The girls walked for {0}.", "showHints": false}', '{"answers": ["two hours"], "caseSensitive": false}', 'FILL_IN_BLANK', 'medium', null, 1.00, null, null, '');
