INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('6dfaf54d-be54-4932-9939-8fa5e6e0e8da', 'LWW_Q2_2025_MOV_007', 'Điền vào chỗ trống', '{"hints": [], "title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "They walked slowly and quietly for two hours. They saw birds and they saw some fish which were swimming in the river. Then, they saw a big brown bear. The children shouted, \"Help!\" and started to run. They were very frightened. Jane stopped and looked back. \"Stop!\" she shouted loudly and all the girls stopped. \"What''s the matter?\" they asked Jane. When they looked again, they couldn''t see the bear.", "imageUrl": "questions/images/1773883656748_24bfd055_q2_mov_rw_p5_2.png", "question": "All the children {0} and started to run when they saw a bear.", "showHints": false}', '{"answers": ["shouted"], "caseSensitive": false}', 'FILL_IN_BLANK', 'medium', null, 1.00, null, null, '');
INSERT INTO public.question_banks (id, code, title, content, correct_answer, question_type, difficulty, skill, points, subject_id, exam_level, explanation) VALUES ('dec414b6-b7f0-429c-8083-20b86060ab11', 'LWW_Q2_2025_MOV_008', 'Điền vào chỗ trống', '{"hints": [], "title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "The girls walked to the river again. When they got there, they saw the bear. It had a fish. \"It''s eating its dinner,\" Jane said. They started to laugh. \"I''m hungry, too,\" said Daisy. \"Come on! Let''s go home!\" And they went back to the house to have their supper.", "imageUrl": "questions/images/1773884433261_2dda594a_q2_mov_rw_p5_3.png", "question": "The girls saw {0} at the river.", "showHints": false}', '{"answers": ["the bear"], "caseSensitive": false}', 'FILL_IN_BLANK', 'medium', null, 1.00, null, null, '');
