INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('bb575263-8012-4f04-8d8e-dacdb0060598', '{"title": "Đọc câu hỏi, chọn câu trả lời phù hợp nhất", "content": "", "imageUrl": "questions/images/1773830107181_5725e724_q2_mov_rw_p2.png"}', 1, '7', null, '70fc9012-71f5-4e93-bc33-d8e59a0329e0');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('22e8392f-4e85-4239-bf24-5c2984d0f32e', '{"title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "Daisy lives with her parents and three sisters, Vicky, Sally and Jane, in the city. Last month, they went on holiday to the mountains. On the first day, the girls went for a walk in the forest.", "imageUrl": "questions/images/1773883159520_309bce44_q2_mov_rw_p5_1.png"}', 1, '10', null, '70fc9012-71f5-4e93-bc33-d8e59a0329e0');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('5c4a2e65-04aa-4540-8e96-68bf215e9e10', '{"title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "They walked slowly and quietly for two hours. They saw birds and they saw some fish which were swimming in the river. Then, they saw a big brown bear. The children shouted, \"Help!\" and started to run. They were very frightened. Jane stopped and looked back. \"Stop!\" she shouted loudly and all the girls stopped. \"What''s the matter?\" they asked Jane. When they looked again, they couldn''t see the bear.", "imageUrl": "questions/images/1773883656748_24bfd055_q2_mov_rw_p5_2.png"}', 2, '10', null, '70fc9012-71f5-4e93-bc33-d8e59a0329e0');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('7d462c5f-7c02-464a-b539-6bc5d8a4a537', '{"title": "Nhìn tranh, kể truyện, điền từ để hoàn thành câu chuyện: ''A walk in the forest''", "content": "The girls walked to the river again. When they got there, they saw the bear. It had a fish. \"It''s eating its dinner,\" Jane said. They started to laugh. \"I''m hungry, too,\" said Daisy. \"Come on! Let''s go home!\" And they went back to the house to have their supper.", "imageUrl": "questions/images/1773884433261_2dda594a_q2_mov_rw_p5_3.png"}', 3, '10', null, '70fc9012-71f5-4e93-bc33-d8e59a0329e0');
