ive": false}', 1.00, 'WORD_FILL_PARAGRAPH', '', '70fc9012-71f5-4e93-bc33-d8e59a0329e0', '8', 8, 34, null, 'd29e8af4-952a-4a38-bcb7-b8e99e5eb489', 'READING', false, null);
